formulas.expression:
"Attention ! La tâche : " + BLANKVALUE({!Recuperer_tache_at_same_dates.Name}, "Tâche sans nom") + " allant du " + /* DEBUT : Jour avec 0 */ IF(DAY(DATEVALUE({!Recuperer_tache_at_same_dates.Date_debut__c})) < 10, "0", "") + TEXT(DAY(DATEVALUE({!Recuperer_tache_at_same_dates.Date_debut__c}))) + "/" + /* DEBUT : Mois avec 0 */ IF(MONTH(DATEVALUE({!Recuperer_tache_at_same_dates.Date_debut__c})) < 10, "0", "") + TEXT(MONTH(DATEVALUE({!Recuperer_tache_at_same_dates.Date_debut__c}))) + "/" + TEXT(YEAR(DATEVALUE({!Recuperer_tache_at_same_dates.Date_debut__c}))) +
" au " +
/* FIN : Jour avec 0 */ IF(DAY(DATEVALUE({!Recuperer_tache_at_same_dates.Date_de_fin__c})) < 10, "0", "") + TEXT(DAY(DATEVALUE({!Recuperer_tache_at_same_dates.Date_de_fin__c}))) + "/" + /* FIN : Mois avec 0 */ IF(MONTH(DATEVALUE({!Recuperer_tache_at_same_dates.Date_de_fin__c})) < 10, "0", "") + TEXT(MONTH(DATEVALUE({!Recuperer_tache_at_same_dates.Date_de_fin__c}))) + "/" + TEXT(YEAR(DATEVALUE({!Recuperer_tache_at_same_dates.Date_de_fin__c}))) + " existe déjà pour l'utilisateur "+ {!Recuperer_tache_at_same_dates.User__r.LastName}+" "+{!Recuperer_tache_at_same_dates.User__r.FirstName}
